from zeep import Client, Settings
from zeep.transports import Transport
from requests import Session
from requests.auth import HTTPBasicAuth

def get_policy_details(policy_number, customer_name):
    wsdl = 'http://www.example.com/insurance?wsdl'
    session = Session()
    session.auth = HTTPBasicAuth('username', 'password')
    transport = Transport(session=session)
    settings = Settings(strict=False, xml_huge_tree=True)
    client = Client(wsdl=wsdl, transport=transport, settings=settings)

    with client.settings(strict=False):
        try:
            response = client.service.GetPolicyDetails(
                PolicyNumber=policy_number,
                CustomerName=customer_name
            )
            return response
        except Exception as e:
            return str(e)

if __name__ == "__main__":
    policy_number = input("Enter Policy Number: ")
    customer_name = input("Enter Customer Name: ")
    result = get_policy_details(policy_number, customer_name)
    print(result)